 22→  background: transparent;
 23→}
 24→
 25→.group {
 26→  display: flex;
 27→  align-items: center;
 28→  gap: 2px;
 29→  padding: var(--space-xs) var(--space-sm);
 30→  background: rgba(0, 0, 0, 0.02);
 31→  border-radius: var(--radius-md);
 32→  flex-shrink: 0;
 33→}
 34→
 35→.group + .group {
 36→  border-left: none;
 37→}
 38→
 39→.divider {
 40→  width: 1px;
 41→  height: 24px;
 42→  background: rgba(0, 0, 0, 0.08);
 43→  margin: 0 var(--space-xs);
 44→  flex-shrink: 0;
 45→}
 46→
 47→/* Icon button base (36x36) */
 48→.btn {
 49→  display: flex;
 50→  align-items: center;
 51→  justify-content: center;
 52→  width: 36px;
 53→  height: 36px;
 54→  padding: 0;
 55→  border-radius: var(--radius-sm);
 56→  border: 1px solid transparent;
 57→  font-size: 12px;
 58→  font-weight: 500;
 59→  letter-spacing: 0.01em;
 60→  color: var(--color-text-secondary);
 61→  box-shadow: inset 0 -1px 0 rgba(0, 0, 0, 0.04);
 62→  transition: background var(--duration-fast), color var(--duration-fast), border-color var(--duration-fast), transform var(--duration-micro) var(--ease-tactile), box-shadow var(--duration-fast);
 63→  white-space: nowrap;
 64→  position: relative;
 65→}
 66→
 67→.btn:hover {
 68→  background: rgba(0, 0, 0, 0.04);
 69→  border-color: rgba(0, 0, 0, 0.06);
 70→  color: var(--color-text-primary);
 71→  transform: translateY(-1px);
 72→  box-shadow: var(--shadow-hover);
 73→}
 74→
 75→.btn:active {
 76→  transform: scale(0.97);
 77→  box-shadow: var(--shadow-pressed);
 78→}
 79→
 80→.btn:disabled {
 81→  opacity: 0.35;
 82→  cursor: not-allowed;
 83→}
 84→
 85→.btn:disabled:hover {
 86→  background: transparent;
 87→  border-color: transparent;
 88→  color: var(--color-text-secondary);
 89→  transform: none;
 90→  box-shadow: inset 0 -1px 0 rgba(0, 0, 0, 0.04);
 91→}
 92→
 93→.btn:disabled:active {
 94→  transform: none;
 95→  box-shadow: inset 0 -1px 0 rgba(0, 0, 0, 0.04);
 96→}
 97→
 98→.icon {
 99→  width: 18px;
100→  height: 18px;
101→  display: block;
102→}
103→
104→/* Save with dirty pulsing dot via data attribute */
105→.saveBtn {
106→  composes: btn;
107→}
108→
109→.saveBtn[data-dirty="true"]::after {
110→  content: '';
111→  position: absolute;
112→  top: 5px;
113→  right: 5px;
114→  width: 6px;
115→  height: 6px;
116→  border-radius: 50%;
117→  background: var(--color-active-glow);
118→  box-shadow: 0 0 6px rgba(212, 169, 76, 0.40);
119→  animation: warmPulse 2s ease-in-out infinite;
120→}
121→
122→@keyframes warmPulse {
123→  0%, 100% {
124→    box-shadow: 0 0 6px rgba(212, 169, 76, 0.40);
125→    opacity: 1;
126→  }
127→  50% {
128→    box-shadow: 0 0 12px rgba(212, 169, 76, 0.60);
129→    opacity: 0.6;
130→  }
131→}
132→
133→/* Segmented pill control for view modes */
134→.segmentedGroup {
135→  display: flex;
136→  align-items: center;
137→  background: var(--color-segment-bg);
138→  border-radius: var(--radius-md);
139→  padding: 2px;
140→  gap: 1px;
141→  flex-shrink: 0;
142→}
143→
144→.segmentedBtn {
145→  display: flex;
146→  align-items: center;
147→  justify-content: center;
148→  height: 30px;
149→  padding: 0 10px;
150→  border-radius: calc(var(--radius-md) - 2px);
151→  font-size: 11px;
152→  font-weight: 500;
153→  color: var(--color-text-secondary);
154→  background: transparent;
155→  transition: background var(--duration-fast), color var(--duration-fast), box-shadow var(--duration-fast);
156→  white-space: nowrap;
157→  cursor: pointer;
158→}
159→
160→.segmentedBtn:hover {
161→  color: var(--color-text-primary);
162→  background: rgba(0, 0, 0, 0.04);
163→}
164→
165→.segmentedBtnActive {
