175→  font-family: var(--font-heading);
176→  font-size: 10px;
177→  font-weight: 600;
178→  text-transform: uppercase;
179→  letter-spacing: 0.1em;
180→  color: var(--color-text-secondary);
181→  white-space: nowrap;
182→  margin-right: 4px;
183→}
184→
185→/* Tool palette - inline row */
