.sidebar {
  background: var(--color-panel-bg);
  border-right: 1px solid var(--color-border);
  overflow-y: auto;
  padding: var(--space-lg);
  display: flex;
  flex-direction: column;
  gap: var(--space-lg);
}

.section {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
}

.sectionHeader {
  display: flex;
  align-items: center;
  gap: 6px;
  width: 100%;
  padding: 2px 4px;
  border-radius: var(--radius-sm);
  background: transparent;
  text-align: left;
  transition: background var(--duration-fast);
  border-bottom: 1px solid var(--color-accent);
  padding-bottom: 6px;
}

.sectionHeaderClickable {
  cursor: pointer;
}

.sectionHeaderClickable:hover {
  background: rgba(0, 0, 0, 0.04);
}

.sectionHeaderClickable:hover .sectionTitle {
  color: var(--color-text-primary);
}

.sectionTitle {
  font-family: var(--font-heading);
  font-size: 12px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--color-text-primary);
  transition: color var(--duration-fast);
}

/* SVG chevron */
.chevron {
  width: 14px;
  height: 14px;
  flex-shrink: 0;
  color: var(--color-text-secondary);
  transition: transform 0.15s ease;
}

.chevronCollapsed {
  transform: rotate(-90deg);
}

.chevronIcon {
  width: 14px;
  height: 14px;
  display: block;
}

/* Section header with action button */
.sectionHeaderRow {
  display: flex;
  align-items: center;
  width: 100%;
}

.sectionHeaderContent {
  flex: 1;
  min-width: 0;
}

.sectionAddBtn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
  border-radius: var(--radius-sm);
  color: var(--color-text-secondary);
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  transition: background var(--duration-fast), color var(--duration-fast);
  flex-shrink: 0;
}

.sectionAddBtn:hover {
  background: rgba(0, 0, 0, 0.06);
  color: var(--color-accent);
}

.sectionAddBtn:active {
  transform: scale(0.92);
}

.count {
  margin-left: auto;
  font-size: 11px;
  color: var(--color-active-glow);
  background: var(--color-active-glow-subtle);
  padding: 0 6px;
  border-radius: 10px;
  line-height: 18px;
  font-weight: 600;
}

/* Sticky floor context header */
.contextHeader {
  position: sticky;
  top: 0;
  z-index: 2;
  padding: 6px 4px;
  font-family: var(--font-heading);
  font-size: 11px;
  font-weight: 600;
  color: var(--color-active-glow);
  background: var(--color-sticky-bg);
  backdrop-filter: blur(6px);
  border-bottom: 1px solid var(--color-active-glow-border);
  margin-bottom: var(--space-xs);
}

.projectName {
  width: 100%;
  height: 28px;
  padding: 0 var(--space-sm);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  font-size: 13px;
  font-weight: 500;
  background: var(--color-surface-elevated);
  color: var(--color-text-primary);
  transition: border-color var(--duration-fast), box-shadow var(--duration-fast);
}

.projectName:focus {
  outline: none;
  border-color: var(--color-accent);
  box-shadow: 0 0 0 2px var(--color-accent-subtle);
}

.item {
  display: flex;
  align-items: center;
  width: 100%;
  padding: var(--space-xs) var(--space-sm);
  border: none;
  border-left: 2px solid transparent;
  border-radius: var(--radius-sm);
  background: transparent;
  font-size: 12px;
  text-align: left;
  cursor: pointer;
  color: var(--color-text-primary);
  transition: background var(--duration-fast), color var(--duration-fast), border-color var(--duration-fast);
}

.item:hover {
  background: rgba(0, 0, 0, 0.04);
  border-left-color: rgba(0, 0, 0, 0.08);
}

.item:disabled {
  cursor: not-allowed;
  opacity: 0.55;
}

.itemSelected {
  background: var(--color-active-glow-subtle);
  color: var(--color-active-glow);
  font-weight: 500;
  border-left-color: var(--color-active-glow);
}

.itemSelected:hover {
  background: rgba(212, 169, 76, 0.18);
}

