  display: flex;
  align-items: stretch;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  background: var(--color-card-bg);
  transition: background var(--duration-fast), border-color var(--duration-fast), transform var(--duration-fast), box-shadow var(--duration-fast);
  overflow: hidden;
}

.floorCard:hover {
  background: var(--color-card-bg-hover);
  transform: translateY(-1px);
  box-shadow: var(--shadow-sm);
}

.floorCard:hover .floorActions {
  opacity: 1;
}

.floorCardActive {
  border-color: var(--color-active-glow);
  background: var(--color-active-glow-subtle);
}

.floorButton {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 2px;
  padding: 8px 10px;
  background: transparent;
  border: none;
  cursor: pointer;
  min-width: 0;
}

.floorName {
  font-size: 12px;
  font-weight: 500;
  color: var(--color-text-primary);
}

.floorMeta {
  font-size: 10px;
  color: var(--color-text-secondary);
}

.floorActions {
  display: flex;
  align-items: center;
  gap: 2px;
  padding: 0 6px;
  opacity: 0;
  transition: opacity var(--duration-fast);
}

.floorActionBtn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 26px;
  height: 26px;
  border: none;
  border-radius: var(--radius-sm);
  background: transparent;
  color: var(--color-text-secondary);
  cursor: pointer;
  transition: background var(--duration-fast), color var(--duration-fast);
}

.floorActionBtn:hover:not(:disabled) {
  background: rgba(0, 0, 0, 0.06);
  color: var(--color-text-primary);
}

.floorActionBtn:active:not(:disabled) {
  transform: scale(0.92);
}

.floorActionBtn:disabled {
  cursor: not-allowed;
  opacity: 0.5;
}

.floorActionDanger:hover:not(:disabled) {
  background: var(--color-danger-ghost-bg-hover);
  color: var(--color-danger);
}

.floorActionIcon {
  width: 14px;
  height: 14px;
  display: block;
}

